import pytest
from flatten_dict import flatten_dict  # Assuming the function is in a module named flatten_dict

class TestFlattenDict:
    def test_happy_path_nested_dict(self):
        """Test flattening a nested dictionary."""
        input_dict = {'a': {'b': 1, 'c': {'d': 2}}}
        expected = {'a.b': 1, 'a.c.d': 2}
        assert flatten_dict(input_dict) == expected

    def test_empty_dict(self):
        """Test flattening an empty dictionary."""
        input_dict = {}
        expected = {}
        assert flatten_dict(input_dict) == expected

    def test_no_nesting(self):
        """Test flattening a dictionary with no nesting."""
        input_dict = {'a': 1, 'b': 2}
        expected = {'a': 1, 'b': 2}
        assert flatten_dict(input_dict) == expected

    def test_custom_separator(self):
        """Test flattening with a custom separator."""
        input_dict = {'a': {'b': 1, 'c': {'d': 2}}}
        expected = {'a_b': 1, 'a_c_d': 2}
        assert flatten_dict(input_dict, sep='_') == expected

    def test_with_parent_key(self):
        """Test flattening with a provided parent_key."""
        input_dict = {'b': 1, 'c': {'d': 2}}
        expected = {'a.b': 1, 'a.c.d': 2}
        assert flatten_dict(input_dict, parent_key='a') == expected

    def test_mixed_types(self):
        """Test flattening a dictionary with mixed value types (lists, etc.)."""
        input_dict = {'a': [1, 2], 'b': {'c': 3}}
        expected = {'a': [1, 2], 'b.c': 3}
        assert flatten_dict(input_dict) == expected

    def test_deep_nesting(self):
        """Test flattening a deeply nested dictionary."""
        input_dict = {'a': {'b': {'c': {'d': {'e': 5}}}}}
        expected = {'a.b.c.d.e': 5}
        assert flatten_dict(input_dict) == expected

    def test_non_dict_input_raises_error(self):
        """Test that passing a non-dictionary raises an AttributeError."""
        with pytest.raises(AttributeError):
            flatten_dict("not a dict")

    @pytest.mark.parametrize("input_dict, expected", [
        ({}, {}),
        ({'a': 1}, {'a': 1}),
        ({'a': {'b': 2}}, {'a.b': 2}),
        ({'a': {'b': {'c': 3}}}, {'a.b.c': 3}),
    ])
    def test_parametrized_cases(self, input_dict, expected):
        """Parametrized tests for various inputs."""
        assert flatten_dict(input_dict) == expected
